  /**
   * Perform health checks on all services
   */
  async performHealthCheck(): Promise<{
    overall: 'HEALTHY' | 'WARNING' | 'CRITICAL';
    services: ServiceHealthCheck[];
    summary: {
      healthy: number;
      warning: number;
      critical: number;
    };
  }> {
    try {
      const healthChecks: ServiceHealthCheck[] = [];
      
      // Simulate health checks for each service
      const serviceNames = Object.keys(this.services);
      
      for (const serviceName of serviceNames) {
        const status = this.simulateHealthStatus();
        healthChecks.push({
          service: serviceName,
          status: status.status,
          message: status.message,
          metrics: status.metrics,
          lastChecked: new Date(),
          dependencies: status.dependencies,
        });
      }

      // Calculate summary
      const summary = healthChecks.reduce((acc, check) => {
        switch (check.status) {
          case 'HEALTHY':
            acc.healthy++;
            break;
          case 'WARNING':
            acc.warning++;
            break;
          case 'CRITICAL':
            acc.critical++;
            break;
        }
        return acc;
      }, { healthy: 0, warning: 0, critical: 0 });

      // Determine overall status
      let overall: 'HEALTHY' | 'WARNING' | 'CRITICAL' = 'HEALTHY';
      if (summary.critical > 0) {
        overall = 'CRITICAL';
      } else if (summary.warning > 0) {
        overall = 'WARNING';
      }

      logger.info('Service operations health check completed', {
        overall,
        summary,
        servicesChecked: healthChecks.length,
      });

      return {
        overall,
        services: healthChecks,
        summary,
      };
    } catch (error) {
      logger.error('Failed to perform health check', error);
      throw error;
    }
  }

